sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county ?sviRecord ?socioeconomicScore ?coastalWindEventCount
WHERE {
  ?county a goo:County ;
          goo:locatedInState gokg:LouisianaState .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear 2018 ;
             goo:sviSocioeconomicTheme ?socioeconomicScore .
  FILTER (?socioeconomicScore >= 0.85)
  {
    SELECT ?county (COUNT(DISTINCT ?event) AS ?coastalWindEventCount)
    WHERE {
      ?event a goo:StormEventRecord ;
             goo:occurredInState gokg:LouisianaState ;
             goo:occurredInCounty ?county ;
             goo:stormEventType ?eventType ;
             goo:eventStartTime ?eventStart .
      FILTER (YEAR(?eventStart) = 2018)
      FILTER (REGEX(STR(?eventType), "Wind", "i"))
    }
    GROUP BY ?county
  }
  FILTER (?coastalWindEventCount >= 10 && ?coastalWindEventCount <= 14)
}
ORDER BY DESC(?socioeconomicScore) DESC(?coastalWindEventCount) ?county
LIMIT 10
